// Models/Asset.cs
namespace KmgAssets.Models;

public class Asset
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Department { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
}

// ViewModels/AssetsPageVM.cs
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using KmgAssets.Models;
using System.Collections.ObjectModel;

namespace KmgAssets.ViewModels;

public partial class AssetsPageVM : ObservableObject
{
    private readonly List<Asset> _all = new()
    {
        new() { Id = 1, Name = "Pump-102", Department = "Production", Status = "Active" },
        new() { Id = 2, Name = "Valve-44", Department = "Maintenance", Status = "Repair" },
        new() { Id = 3, Name = "Compressor-7", Department = "Production", Status = "Active" },
    };

    public ObservableCollection<Asset> Filtered { get; } = new();

    public AssetsPageVM() => ApplyFilter();

    [ObservableProperty]
    private string _searchText = string.Empty;

    partial void OnSearchTextChanged(string value) => ApplyFilter();

    private void ApplyFilter()
    {
        var q = SearchText?.Trim() ?? string.Empty;
        Filtered.Clear();
        var query = string.IsNullOrEmpty(q)
            ? _all
            : _all.Where(a => a.Name.Contains(q, StringComparison.OrdinalIgnoreCase));
        foreach (var item in query) Filtered.Add(item);
    }

    [RelayCommand]
    private void Delete(Asset asset)
    {
        _all.Remove(asset);
        Filtered.Remove(asset);
    }

    [RelayCommand]
    private async Task OpenAsync(Asset asset)
    {
        await Shell.Current.DisplayAlert("Актив", asset.Name, "OK");
    }
}
